import{_ as r,o as t,c as p,j as e,a as s,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"长生不老药（伪）","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/9.消耗品/1.D级/长生不老药（伪）.md","filePath":"4.资源分区/7.物品与装备/9.消耗品/1.D级/长生不老药（伪）.md"}'),o={name:"4.资源分区/7.物品与装备/9.消耗品/1.D级/长生不老药（伪）.md"};function d(_,a,l,i,b,c){return t(),p("div",null,[...a[0]||(a[0]=[e("h1",{id:"长生不老药-伪",tabindex:"-1"},[s("长生不老药（伪） "),e("a",{class:"header-anchor",href:"#长生不老药-伪","aria-label":'Permalink to "长生不老药（伪）"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),n('<h1 id="长生不老药-伪-1" tabindex="-1">长生不老药（伪） <a class="header-anchor" href="#长生不老药-伪-1" aria-label="Permalink to &quot;长生不老药（伪）&quot;">​</a></h1><p>长生不老药（伪）<br> D+500<br> 魔幻本质</p><p>此药的来源以不可考证，只能在古籍传说中寻得一星半点，猰貐、女娲、伏羲、颛顼......<br> 最终得以永生者，都变为了半人半兽的奇异存在……虽然这只是仿制品。<br> 效果：人物在使用该药前，需寻得一兽作为自己的半身，主神将免费提供现实世界内存在的所有无支线生物模板，若st允许，人物也可寻一属于自己的的超凡生物作为半身，这可能会产生一些新的效果，具体由st决定。</p><p>服用并配合古老且神秘的仪式后，人物得以重生为半人半兽的存在，你可以重新定义你的形象，但人身和兽身的特征应该相差不大的分配在你的新形象中，即你不能仅仅长一双耳朵加个尾巴以代表你的兽类特征，这显得太少了，当然你也也不能将自己完全变为兽类，但人头鱼身，人面鸟身等可以。</p><p>你的自此寿命不会因自然因素流逝，且不食五谷，吸风饮露，这意味着无需吃食水分即可存活，获得C级免疫衰老效果。<br> 你开启妖力能量池，在种族上视为人/妖，取不利计算。</p><p>以下分支只能选择一种购买：<br> 若在购买时额外支付750分，还会获得以下效果。<br> 人物若选择的半身，为鱼类等水生生物且新形象中带有腮等器官，则获得等同于基础移动速度的游泳速度，可在水下自由呼吸。</p><p>若是在购买时额外支付2000分，还会获得以下效果。<br> 人物若选择的半身，为鸟类等生物且新形象中带有翅膀等器官，则可以获得飞行能力，机动性为普通。</p><p>若是在购买时额外支付500，还会获得以下效果。<br> 人物若选择的半身为陆上哺乳动物，且形象中带有动物肢体，则获得2dp运动技能的增强加值。</p><p>若在购买时额外支付500分，还会获得以下效果。<br> 人物若选择的半身为爬行生物，且外表皮有鳞片，则获得2点天生防御。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const m=r(o,[["render",d]]);export{f as __pageData,m as default};
